13	 * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
14	 * See the License for the specific language governing permissions and
15	 * limitations under the License.
16	 */
17	
18	#include <float.h>
19	
20	#include "src/fastertransformer/kernels/sampling_topk_kernels.h"
21	#include "src/fastertransformer/kernels/sampling_topp_kernels.h"
22	#include "src/fastertransformer/layers/sampling_layers/TopKSamplingLayer.h"
23	#include "src/fastertransformer/utils/logger.h"
24	#include "src/fastertransformer/utils/memory_utils.h"
25	
26	namespace fastertransformer {
27	
28	template<uint TOP_K_MAX>
29	__global__ void setup_topk_runtime_args(int    batch_size,
30	                                        uint   top_k,
31	                                        uint*  top_ks,
32	                                        int    top_ks_size,
33	                                        float  top_p,
34	                                        float* top_ps,
35	                                        int    top_ps_size,
36	                                        bool*  skip_decode)
37	{
38	    int index = blockIdx.x * blockDim.x + threadIdx.x;
39	    for (int i = index; i < batch_size; i += gridDim.x * blockDim.x) {
40	        uint  k = top_ks_size > 1 ? top_ks[i] : top_k;
41	        float p = top_ps_size > 1 ? top_ps[i] : top_p;
42	        if (k == 0 && p == 0.0f) {
43	            // FT's topp implementation does not support topp = 0.0f, but it equivalent to greedy search.
44	            // So, we set the topk = 1 as an alternative solution.
45	            k = 1;
46	        }
47	        if (k > 0 && p == 0.0f) {
48	            // for compatibility <= FT5.0.
49	            // This case corresponds to the old topk sampling, which is equivalent to
50	            // the old topk_topp sampling with topp=1.0f. TopKSamplingLayer and
51	            // TopKTopPSamplingLayer are now merged by TopKSamplingLayer. Thus, we
52	            // replace the case topk>0 and topp=0.0f by topk>0 and topp=1.0f for the
53	            // compatibility.
54	            p = 1.0f;
55	        }
56	        // Clip k value. A topk sampling kernel supports up to TOP_K_MAX=64.
57	        top_ks[i] = k > TOP_K_MAX ? TOP_K_MAX : k;
58	        if (k > TOP_K_MAX) {
59	            printf("[WARNING] topk (%d) is larger than max supported number (%d) for token %d"
60	                   " clip to max supported number %d. \n",
61	                   k,
62	                   TOP_K_MAX,
63	                   i,
64	                   top_ks[i]);
65	        }
66	        // Clip p value if it is out of range. range = [0.0, 1.0].
67	        top_ps[i] = p < 0.0f ? 0.0f : (p > 1.0f ? 1.0f : p);
68	        if (p < 0.0f || p > 1.0f) {
69	            printf("[WARNING] topp (%f) is out of range ([0.0, 1.0f]) for token %d"
70	                   " clip to closest number %f.\n",
71	                   p,
72	                   i,
73	                   top_ps[i]);
74	        }
75	        skip_decode[i] = k == 0;
76	    }
77	}
78	
79	template<typename T>
80	void TopKSamplingLayer<T>::allocateBuffer()
81	{
82	    FT_CHECK(false);
83	}
84	
85	template<typename T>
86	void TopKSamplingLayer<T>::allocateBuffer(size_t batch_size, Tensor top_k, Tensor top_p)
87	{
88	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
89	    BaseSamplingLayer<T>::allocateBuffer(batch_size, top_k, top_p);
90	    uint max_top_k = top_k.size() > 0 ? top_k.max<uint>() : 1;
91	    if (max_top_k == 0) {
92	        // for safety. TopKSamplingLayer handles a case of top_k=0 and top_p=0 as
93	        // a greedy decode, i.e. top_k=1, although such case has max_top_k=0.
94	        max_top_k = 1;
95	    }
96	    invokeTopKSampling<T>(nullptr,
97	                          sampling_workspace_size_,
98	                          nullptr,
99	                          nullptr,
100	                          nullptr,
101	                          nullptr,
102	                          nullptr,
103	                          nullptr,
104	                          nullptr,
105	                          max_top_k,
106	                          1.0f,
107	                          vocab_size_padded_,
108	                          nullptr,
109	                          stream_,
110	                          batch_size,
111	                          skip_decode_buf_);
112	    sampling_workspace_ = allocator_->reMalloc(sampling_workspace_, sampling_workspace_size_, false);
113	    runtime_top_k_buf_ =
114	        reinterpret_cast<uint*>(allocator_->reMalloc(runtime_top_k_buf_, sizeof(uint) * batch_size, false));
115	    runtime_top_p_buf_ =
116	        reinterpret_cast<float*>(allocator_->reMalloc(runtime_top_p_buf_, sizeof(float) * batch_size, false));
117	    is_allocate_buffer_ = true;
118	}
