120	template<typename T>
121	void TopKSamplingLayer<T>::freeBuffer()
122	{
123	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
124	    if (is_allocate_buffer_) {
125	        allocator_->free((void**)(&sampling_workspace_));
126	        allocator_->free((void**)(&runtime_top_k_buf_));
127	        allocator_->free((void**)(&runtime_top_p_buf_));
128	    }
129	    BaseSamplingLayer<T>::freeBuffer();
130	    is_allocate_buffer_ = false;
131	}
132	
133	template<typename T>
134	void TopKSamplingLayer<T>::setup(const size_t batch_size, const size_t beam_width, TensorMap* runtime_args)
135	{
136	    // Setup runtime topk and topp arguments.
137	    //
138	    // runtime_args:
139	    //     runtime_top_k [1] or [batch_size] on cpu, optional, uint.
140	    //     runtime_top_p [1] or [batch_size] on cpu, optional, float.
141	    //     temperature [1] or [batch_size] on cpu, optional
142	    //     repetition_penalty [1] or [batch_size] on cpu, optional
143	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
144	    BaseSamplingLayer<T>::setup(batch_size, beam_width, runtime_args);
145	
146	    uint         tmp_top_k     = 0;
147	    const Tensor runtime_top_k = runtime_args->isExist("runtime_top_k") ?
148	                                     runtime_args->at("runtime_top_k") :
149	                                     Tensor(MEMORY_CPU, TYPE_UINT32, {1}, &tmp_top_k);
150	    const Tensor runtime_top_p = runtime_args->isExist("runtime_top_p") ? runtime_args->at("runtime_top_p") : Tensor();
151	    const size_t runtime_top_k_size = runtime_top_k.size();
152	    const size_t runtime_top_p_size = runtime_top_p.size();
153	
154	    uint  top_k = runtime_top_k.max<uint>();
155	    float top_p = runtime_top_p_size == 0 ? 0.0f : runtime_top_p.getVal<float>();
156	
157	    if (runtime_top_k_size > 1) {
158	        FT_CHECK_WITH_INFO(
159	            runtime_top_k.size() == batch_size,
160	            fmtstr("runtime_top_k.size() (%d) == batch_size (%d) is not satisfied!", runtime_top_k.size(), batch_size));
161	        cudaAutoCpy(runtime_top_k_buf_, runtime_top_k.getPtr<uint>(), batch_size, stream_);
162	    }
163	    if (runtime_top_p_size > 1) {
164	        FT_CHECK_WITH_INFO(
165	            runtime_top_p.size() == batch_size,
166	            fmtstr("runtime_top_p.size() (%d) == batch_size (%d) is not satisfied!", runtime_top_p.size(), batch_size));
167	        cudaAutoCpy(runtime_top_p_buf_, runtime_top_p.getPtr<float>(), batch_size, stream_);
168	    }
169	
170	    dim3 block(std::min((int)batch_size, 256));
171	    dim3 grid(div_up((int)batch_size, (int)block.x));
172	    // support top_k up to 1024.
173	    setup_topk_runtime_args<1024><<<grid, block, 0, stream_>>>(batch_size,
174	                                                               top_k,
175	                                                               runtime_top_k_buf_,
176	                                                               runtime_top_k_size,
177	                                                               top_p,
178	                                                               runtime_top_p_buf_,
179	                                                               runtime_top_p_size,
180	                                                               skip_decode_buf_);
181	    cudaAutoCpy(skip_decode_, skip_decode_buf_, batch_size, stream_);
182	    uint* runtime_top_ks = new uint[batch_size];
183	    cudaAutoCpy(runtime_top_ks, runtime_top_k_buf_, batch_size, stream_);
184	    runtime_max_top_k_ = static_cast<int>(*std::max_element(runtime_top_ks, runtime_top_ks + batch_size));
185	    delete[] runtime_top_ks;
186	}
187	
188	template<typename T>
189	void TopKSamplingLayer<T>::runSampling(TensorMap* output_tensors, TensorMap* input_tensors)
190	{
191	    // input_tensors:
192	    //      logits [local_batch_size, vocab_size_padded]
193	    //      embedding_bias [vocab_size_padded], optional
194	    //      step [1] on cpu
195	    //      max_input_length [1] on cpu
196	    //      input_lengths [local_batch_size], optional
197	    //      ite [1] on cpu
198	
199	    // output_tensors:
200	    //      output_ids [max_seq_len, batch_size]
201	    //      finished [local_batch_size], optional
202	    //      sequence_length [local_batch_size], optional
203	    //      cum_log_probs [batch_size], must be float*, optional
204	    //          The cumultative log probability of generated tokens.
205	    //      output_log_probs [local_batch_size], must be float*, optional
206	    //          The log probs at the current step.
207	
208	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
209	    FT_CHECK(input_tensors->size() >= 4);
210	    FT_CHECK(output_tensors->size() >= 1);
211	
212	    const int batch_size       = output_tensors->at("output_ids").shape[1];
213	    const int local_batch_size = input_tensors->at("logits").shape[0];
214	    const int ite              = input_tensors->at("ite").getVal<int>();
215	    const int step             = input_tensors->at("step").getVal<int>();
216	
217	    // in case of skip any, the logit value is already copied and processed.
218	    T* logits = !skip_any_ ? input_tensors->at("logits").getPtr<T>() : runtime_logits_buf_;
219	
220	    invokeAddBiasEndMask(logits,
221	                         (T*)(nullptr),
222	                         input_tensors->at("end_id").getPtr<const int>(),
223	                         output_tensors->at("finished", Tensor{MEMORY_GPU, TYPE_INVALID, {}, nullptr}).getPtr<bool>(),
224	                         local_batch_size,
225	                         vocab_size_,
226	                         vocab_size_padded_,
227	                         stream_);
228	    sync_check_cuda_error();
229	
230	    float* cum_log_probs =
231	        output_tensors->isExist("cum_log_probs") ? output_tensors->at("cum_log_probs").getPtr<float>() : nullptr;
232	    float* output_log_probs =
233	        output_tensors->isExist("output_log_probs") ? output_tensors->at("output_log_probs").getPtr<float>() : nullptr;
234	
235	    if (cum_log_probs != nullptr || output_log_probs != nullptr) {
236	        invokeAddBiasSoftMax(
237	            logits,
238	            (T*)(nullptr),
239	            input_tensors->at("end_id").getPtr<int>(),
240	            output_tensors->at("finished", Tensor{MEMORY_GPU, TYPE_INVALID, {}, nullptr}).getPtr<bool>(),
241	            local_batch_size,
242	            vocab_size_padded_,
243	            vocab_size_,
244	            stream_);
245	        sync_check_cuda_error();
246	    }
247	
248	    invokeBatchTopKSampling(
249	        sampling_workspace_,
250	        sampling_workspace_size_,
251	        logits,
252	        output_tensors->at("output_ids").getPtrWithOffset<int>(step * batch_size + ite * local_batch_size),
253	        output_tensors->at("sequence_length", Tensor{MEMORY_GPU, TYPE_INVALID, {}, nullptr}).getPtr<int>(),
254	        output_tensors->at("finished", Tensor{MEMORY_GPU, TYPE_INVALID, {}, nullptr}).getPtr<bool>(),
255	        cum_log_probs,
256	        output_log_probs,
257	        curandstate_buf_ + ite * local_batch_size,
258	        (int)runtime_max_top_k_,  // useless because runtime_top_k_buf_ is never nullptr. Keep for legacy.
259	        (int*)(runtime_top_k_buf_ + ite * local_batch_size),
260	        1.0f,  // useless because runtime_top_p_buf_ is never nullptr. Keep for legacy.
261	        runtime_top_p_buf_ + ite * local_batch_size,
262	        vocab_size_padded_,
263	        input_tensors->at("end_id").getPtr<int>(),
264	        stream_,
265	        local_batch_size,
266	        skip_decode_buf_ + ite * local_batch_size);
267	    sync_check_cuda_error();
268	}
