30	static __global__ void set_topp_runtime_args(int             batch_size,
31	                                             uint            top_k,
32	                                             uint*           top_ks,
33	                                             int             top_ks_size,
34	                                             float           top_p,
35	                                             float*          top_ps,
36	                                             int             top_ps_size,
37	                                             bool*           skip_decode,
38	                                             float*          initial_top_p_buf,
39	                                             float*          top_p_decay_buf,
40	                                             const float*    top_p_decay,
41	                                             float*          top_p_min_buf,
42	                                             const float*    top_p_min,
43	                                             int32_t*        top_p_reset_ids_buf,
44	                                             const uint32_t* top_p_reset_ids)
45	{
46	    /**
47	     * @brief Setup the runtime arguments for topp, broadcasting top_p to top_ps
48	                and top_k to top_ks, copying top_p_decay/top_p_min/top_p_reset_ids
49	                to internal buffers.
50	     *
51	     * \param batch_size            [batch_size]
52	     * \param op_k                  [batch_size]
53	     * \param top_ks                [batch_size]
54	     * \param top_ks_size           [batch_size]
55	     * \param top_p                 [batch_size]
56	     * \param top_ps                [batch_size]
57	     * \param top_ps_size           [batch_size]
58	     * \param skip_decode           [batch_size]
59	     * \param initial_top_p_buf     [batch_size]
60	     * \param top_p_decay_buf       [batch_size]
61	     * \param top_p_decay           [batch_size], optional, must between [0, 1]
62	     * \param top_p_min_buf         [batch_size]
63	     * \param top_p_min             [batch_size], optional, must between [0, 1]
64	     * \param top_p_reset_ids_buf    [batch_size]
65	     * \param top_p_reset_ids        [batch_size], optional
66	     *
67	     */
68	
69	    int index = blockIdx.x * blockDim.x + threadIdx.x;
70	    for (int i = index; i < batch_size; i += gridDim.x * blockDim.x) {
71	        uint  k = top_ks_size > 1 ? top_ks[i] : top_k;
72	        float p = top_ps_size > 1 ? top_ps[i] : top_p;
73	        if (k == 0 && p == 0.0f) {
74	            // FT's topp implementation does not support topp = 0.0f, but it equivalent to greedy search.
75	            // So, we set the topk = 1 as an alternative solution.
76	            k = 1;
77	        }
78	        top_ks[i] = k;
79	        // Clip p value if it is out of range. range = [0.0, 1.0].
80	        top_ps[i] = p < 0.0f ? 0.0f : (p > 1.0f ? 1.0f : p);
81	        if (p < 0.0f || p > 1.0f) {
82	            printf("[WARNING] topp (%f) is out of range ([0.0, 1.0f]) for token %d"
83	                   " clip to closest number %f.\n",
84	                   p,
85	                   i,
86	                   top_ps[i]);
87	        }
88	        skip_decode[i] = k > 0;
89	
90	        initial_top_p_buf[i] = top_ps[i];
91	        top_p_decay_buf[i]   = top_p_decay == nullptr ? 1.0f : top_p_decay[i];
92	        if (top_p_decay_buf[i] > 1.0f || top_p_decay_buf[i] <= 0.0f) {
93	            printf("[WARNING] top_p_decay_buf (%f) is out of range ([0.0, 1.0f]) for token %d,"
94	                   " change to 1.0f.\n",
95	                   top_p_decay_buf[i],
96	                   i);
97	            top_p_decay_buf[i] = 1.0f;
98	        }
99	        top_p_min_buf[i] = top_p_min == nullptr ? 1e-6f : top_p_min[i];  // prevent topp becoming 0.0
100	        if (top_p_min_buf[i] > 1.0f || top_p_min_buf[i] <= 0.0f) {
101	            printf("[WARNING] top_p_min_buf (%f) is out of range ([0.0, 1.0f]) for token %d,"
102	                   " change to 0.5f.\n",
103	                   top_p_min_buf[i],
104	                   i);
105	            top_p_min_buf[i] = 0.5f;
106	        }
107	        top_p_reset_ids_buf[i] = (int32_t)(top_p_reset_ids == nullptr ? -1 : top_p_reset_ids[i]);
108	    }
109	}
