117	template<typename T>
118	void TopPSamplingLayer<T>::allocateBuffer(size_t batch_size, Tensor top_k, Tensor top_p)
119	{
120	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
121	    BaseSamplingLayer<T>::allocateBuffer(batch_size, top_k, top_p);
122	    invokeTopPSampling<T>(nullptr,  // workspace
123	                          sampling_workspace_size_,
124	                          cub_temp_storage_size_,
125	                          nullptr,  // output_ids
126	                          nullptr,  // sequence_length
127	                          nullptr,  // finished_buffer
128	                          nullptr,  // cum_log_probs
129	                          nullptr,  // output_log_probs
130	                          nullptr,  // log_probs
131	                          topp_id_vals_buf_,
132	                          topp_offset_buf_,
133	                          begin_topp_offset_buf_,
134	                          curandstate_buf_,
135	                          batch_size,
136	                          vocab_size_padded_,
137	                          nullptr,
138	                          top_p.size() > 0 ? top_p.max<float>() : 0.0f,
139	                          stream_,
140	                          cuda_device_prop_,
141	                          skip_decode_buf_);
142	    sampling_workspace_ = allocator_->reMalloc(sampling_workspace_, sampling_workspace_size_, true);
143	    runtime_top_k_buf_ =
144	        reinterpret_cast<uint*>(allocator_->reMalloc(runtime_top_k_buf_, sizeof(uint) * batch_size, false));
145	    runtime_top_p_buf_ =
146	        reinterpret_cast<float*>(allocator_->reMalloc(runtime_top_p_buf_, sizeof(float) * batch_size, false));
147	    initial_top_p_buf_ =
148	        reinterpret_cast<float*>(allocator_->reMalloc(initial_top_p_buf_, sizeof(float) * batch_size, false));
149	    top_p_decay_buf_ =
150	        reinterpret_cast<float*>(allocator_->reMalloc(top_p_decay_buf_, sizeof(float) * batch_size, false));
151	    top_p_min_buf_ = reinterpret_cast<float*>(allocator_->reMalloc(top_p_min_buf_, sizeof(float) * batch_size, false));
152	    top_p_reset_ids_buf_ =
153	        reinterpret_cast<int32_t*>(allocator_->reMalloc(top_p_reset_ids_buf_, sizeof(int32_t) * batch_size, false));
154	    topp_id_vals_buf_ = reinterpret_cast<int*>(
155	        allocator_->reMalloc(topp_id_vals_buf_, sizeof(int) * batch_size * vocab_size_padded_, false));
156	    topp_offset_buf_ =
157	        reinterpret_cast<int*>(allocator_->reMalloc(topp_offset_buf_, sizeof(int) * (batch_size + 1), false));
158	    begin_topp_offset_buf_ =
159	        reinterpret_cast<int*>(allocator_->reMalloc(begin_topp_offset_buf_, sizeof(int) * (batch_size + 1), false));
160	    is_allocate_buffer_ = true;
