183	template<typename T>
184	void TopPSamplingLayer<T>::setup(const size_t batch_size, const size_t beam_width, TensorMap* runtime_args)
185	{
186	    /**
187	    * @brief Set up the sampling layer for given runtime arguments.
188	
189	    * runtime_args:
190	    *   \param  runtime_top_k [1] or [batch_size] on cpu, optional.
191	    *   \param  runtime_top_p [1] or [batch_size] on cpu, optional
192	    *   \param  temperature [1] or [batch_size] on cpu, optional
193	    *   \param  repetition_penalty [1] or [batch_size] on cpu, optional
194	    *   \param  top_p_decay [batch_size] on gpu, float, optional
195	    *   \param  top_p_min [batch_size] on gpu, float, optional
196	    *   \param  top_p_reset_ids [batch_size] on gpu, uint32, optional
197	    **/
198	
199	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
200	    BaseSamplingLayer<T>::setup(batch_size, beam_width, runtime_args);
201	    const Tensor runtime_top_p = runtime_args->isExist("runtime_top_p") ? runtime_args->at("runtime_top_p") : Tensor();
202	    const size_t runtime_top_p_size = runtime_top_p.size();
203	    if (runtime_top_p_size == 0) {
204	        std::fill_n(skip_decode_, batch_size, true);
205	        return;
206	    }
207	
208	    uint         tmp_top_k          = 0;
209	    const Tensor runtime_top_k      = runtime_args->isExist("runtime_top_k") ?
210	                                          runtime_args->at("runtime_top_k") :
211	                                          Tensor(MEMORY_CPU, TYPE_UINT32, {1}, &tmp_top_k);
212	    const size_t runtime_top_k_size = runtime_top_k.size();
213	
214	    uint  top_k = runtime_top_k.getVal<uint>();
215	    float top_p = runtime_top_p.getVal<float>();
216	
217	    if (runtime_top_k_size > 1) {
218	        FT_CHECK(runtime_top_k.size() == batch_size);
219	        cudaH2Dcpy(runtime_top_k_buf_, runtime_top_k.getPtr<uint>(), batch_size);
220	    }
221	    if (runtime_top_p_size > 1) {
222	        FT_CHECK(runtime_top_p.size() == batch_size);
223	        cudaH2Dcpy(runtime_top_p_buf_, runtime_top_p.getPtr<float>(), batch_size);
224	    }
225	
226	    dim3 block(std::min((int)batch_size, 256));
227	    dim3 grid(div_up((int)batch_size, (int)block.x));
228	
229	    const float*    top_p_decay     = runtime_args->getPtr<float>("top_p_decay", nullptr);
230	    const float*    top_p_min       = runtime_args->getPtr<float>("top_p_min", nullptr);
231	    const uint32_t* top_p_reset_ids = runtime_args->getPtr<uint32_t>("top_p_reset_ids", nullptr);
232	    set_topp_runtime_args<<<grid, block, 0, stream_>>>(batch_size,
233	                                                       top_k,
234	                                                       runtime_top_k_buf_,
235	                                                       runtime_top_k_size,
236	                                                       top_p,
237	                                                       runtime_top_p_buf_,
238	                                                       runtime_top_p_size,
239	                                                       skip_decode_buf_,
240	                                                       initial_top_p_buf_,
241	                                                       top_p_decay_buf_,
242	                                                       top_p_decay,
243	                                                       top_p_min_buf_,
244	                                                       top_p_min,
245	                                                       top_p_reset_ids_buf_,
246	                                                       top_p_reset_ids);
247	    sync_check_cuda_error();
248	    cudaAutoCpy(skip_decode_, skip_decode_buf_, batch_size, stream_);
249	    float* runtime_top_ps = new float[batch_size];
250	    cudaAutoCpy(runtime_top_ps, runtime_top_p_buf_, batch_size, stream_);
251	    runtime_max_top_p_ = *std::max_element(runtime_top_ps, runtime_top_ps + batch_size);
252	    delete[] runtime_top_ps;
253	}
254	
255	template<typename T>
256	void TopPSamplingLayer<T>::runSampling(TensorMap* output_tensors, TensorMap* input_tensors)
257	{
258	    /**
259	    * input_tensors:
260	    *   \param  logits [local_batch_size, vocab_size_padded]
261	    *   \param  embedding_bias [vocab_size_padded], optional
262	    *   \param  step [1] on cpu
263	    *   \param  max_input_length [1] on cpu
264	    *   \param  input_lengths [local_batch_size], optional
265	    *   \param  ite [1] on cpu
266	
267	    * output_tensors:
268	    *   \param  output_ids [max_seq_len, batch_size]
269	    *   \param  finished [local_batch_size], optional
270	    *   \param  sequence_length [local_batch_size], optional
271	    *   \param  cum_log_probs [batch_size], must be float*, optional
272	    *   \param  The cumultative log probability of generated tokens.
273	    *   \param  output_log_probs [local_batch_size], must be float*, optional
274	                    log probs at the current step.
275	    **/
276	
277	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
278	    FT_CHECK(input_tensors->size() >= 4);
279	    FT_CHECK(output_tensors->size() >= 1);
280	
281	    const int batch_size       = output_tensors->at("output_ids").shape[1];
282	    const int local_batch_size = input_tensors->at("logits").shape[0];
283	    const int step             = input_tensors->at("step").getVal<int>();
284	    const int ite              = input_tensors->at("ite").getVal<int>();
285	
286	    // in case of skip any, the logit value is already copied and processed.
287	    T* logits = !skip_any_ ? input_tensors->at("logits").getPtr<T>() : runtime_logits_buf_;
288	
289	    invokeTopPInitialize(
290	        topp_id_vals_buf_, topp_offset_buf_, begin_topp_offset_buf_, local_batch_size, vocab_size_padded_, stream_);
291	    sync_check_cuda_error();
292	
293	    invokeAddBiasSoftMax(logits,
294	                         (T*)(nullptr),
295	                         input_tensors->at("end_id").getPtr<int>(),
296	                         output_tensors->at("finished", Tensor{MEMORY_GPU, TYPE_INVALID, {}, nullptr}).getPtr<bool>(),
297	                         local_batch_size,
298	                         vocab_size_padded_,
299	                         vocab_size_,
300	                         stream_);
301	    sync_check_cuda_error();
302	
303	    float* cum_log_probs =
304	        output_tensors->isExist("cum_log_probs") ? output_tensors->at("cum_log_probs").getPtr<float>() : nullptr;
305	    float* output_log_probs =
306	        output_tensors->isExist("output_log_probs") ? output_tensors->at("output_log_probs").getPtr<float>() : nullptr;
307	
308	    invokeBatchTopPSampling<T>(
309	        sampling_workspace_,
310	        sampling_workspace_size_,
311	        cub_temp_storage_size_,
312	        output_tensors->at("output_ids").getPtrWithOffset<int>(step * batch_size + ite * local_batch_size),
313	        output_tensors->at("sequence_length", Tensor{MEMORY_GPU, TYPE_INVALID, {}, nullptr}).getPtr<int>(),
314	        output_tensors->at("finished", Tensor{MEMORY_GPU, TYPE_INVALID, {}, nullptr}).getPtr<bool>(),
315	        cum_log_probs,
316	        output_log_probs,
317	        logits,
318	        topp_id_vals_buf_,
319	        topp_offset_buf_,
320	        begin_topp_offset_buf_,
321	        curandstate_buf_ + ite * local_batch_size,
322	        local_batch_size,
323	        vocab_size_padded_,
324	        input_tensors->at("end_id").getPtr<int>(),
325	        runtime_max_top_p_,
326	        runtime_top_p_buf_ + ite * local_batch_size,
327	        stream_,
328	        cuda_device_prop_,
329	        skip_decode_buf_ + ite * local_batch_size);
330	    sync_check_cuda_error();
331	
332	    invokeComputeToppDecay(
333	        runtime_top_p_buf_ + ite * local_batch_size,
334	        initial_top_p_buf_ + ite * local_batch_size,
335	        output_tensors->getPtrWithOffset<int>("output_ids", step * batch_size + ite * local_batch_size),
336	        top_p_decay_buf_ + ite * local_batch_size,
337	        top_p_min_buf_ + ite * local_batch_size,
338	        top_p_reset_ids_buf_ + ite * local_batch_size,
339	        local_batch_size,
340	        stream_);
341	    sync_check_cuda_error();
342	    FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
343	}
