86	                                        cudaStream_t       stream,
87	                                        cublasMMWrapper*   cublas_wrapper,
88	                                        IAllocator*        allocator,
89	                                        bool               is_free_buffer_after_forward,
90	                                        cudaDeviceProp*    cuda_device_prop):
91	    DynamicDecodeBaseLayer(stream, cublas_wrapper, allocator, is_free_buffer_after_forward, cuda_device_prop),
92	    vocab_size_(vocab_size),
93	    vocab_size_padded_(vocab_size_padded)
94	{
