111	template<typename T>
112	void BaseSamplingLayer<T>::setup(const size_t batch_size, const size_t beam_width, TensorMap* runtime_args)
113	{
114	    // Set up the sampling layer for given runtime arguments.
115	    //
116	    // runtime_args:
117	    //     runtime_top_k [1] or [batch_size] on cpu, optional.
118	    //     runtime_top_p [1] or [batch_size] on cpu, optional
119	    //     temperature [1] or [batch_size] on cpu, optional
120	    //     repetition_penalty [1] or [batch_size] on cpu, optional
121	    //     presence_penalty [1] or [batch_size] on cpu, optional,
122	    //         repetition_penalty and presence_penalty are mutually exclusive.
123	    //     min_length [1] or [batch_size] on cpu, optional
124	
125	    FT_LOG_DEBUG(__PRETTY_FUNCTION__);
126	    Tensor runtime_top_k = runtime_args->isExist("runtime_top_k") ? runtime_args->at("runtime_top_k") : Tensor();
127	    Tensor runtime_top_p = runtime_args->isExist("runtime_top_p") ? runtime_args->at("runtime_top_p") : Tensor();
128	    allocateBuffer(batch_size, runtime_top_k, runtime_top_p);
129	
130	    // If runtime argument has single random seed, using this random seed to initialize the random table of all
131	    // sentences. If the argument has [batch_size] random seeds, initializing the random table by different random seeds
132	    // respectively. If no random seed, initialize the random table of all sentences by 0 directly.
133	    if (runtime_args->isExist("random_seed")) {
134	        Tensor random_seeds = runtime_args->at("random_seed");
135	        FT_CHECK_WITH_INFO(random_seeds.shape.size() == 1
136	                               && (random_seeds.size() == 1 || random_seeds.size() == batch_size),
137	                           fmtstr("random_seeds must be of shape [1] or [batch_size(%ld)], got random_seeds.shape=%s",
138	                                  batch_size,
139	                                  vec2str(random_seeds.shape).c_str()));
140	        if (random_seeds.size() == 1) {
141	            invokeCurandInitialize(curandstate_buf_, batch_size, random_seeds.getVal<unsigned long long>(), stream_);
142	            sync_check_cuda_error();
143	        }
144	        else {
145	            unsigned long long* random_seed_ptr = random_seeds.getPtr<unsigned long long>();
146	            cudaAutoCpy(random_seeds_buf_, random_seed_ptr, batch_size, stream_);
147	            invokeCurandBatchInitialize(curandstate_buf_, batch_size, random_seeds_buf_, stream_);
148	            sync_check_cuda_error();
149	        }
150	    }
151	    else {
152	        // Initialize curand states using the default seed 0.
153	        invokeCurandInitialize(curandstate_buf_, batch_size, 0, stream_);
154	    }
155	
156	    // Setup penalties.
157	    const float default_temperature = 1.0f;
158	    Tensor      temperature         = runtime_args->isExist("temperature") ?
159	                                          runtime_args->at("temperature") :
160	                                          Tensor(MEMORY_CPU, TYPE_FP32, {1}, &default_temperature);
161	    if (temperature.size() == 1) {
162	        float tp = temperature.getVal<float>();
163	        deviceFill(temperature_buf_, batch_size, tp, stream_);
164	        std::fill_n(temperature_, batch_size, tp);
165	    }
166	    else {
167	        cudaAutoCpy(temperature_buf_, temperature.getPtr<float>(), batch_size, stream_);
168	        std::copy_n(temperature.getPtr<float>(), batch_size, temperature_);
169	    }
170	
171	    if (runtime_args->isExist("repetition_penalty") || runtime_args->isExist("presence_penalty")) {
172	        FT_CHECK_WITH_INFO(
173	            !(runtime_args->isExist("repetition_penalty") && runtime_args->isExist("presence_penalty")),
174	            "Found ambiguous parameters repetition_penalty and presence_penalty which are mutually exclusive. "
175	            "Please provide one of repetition_penalty or presence_penalty.");
176	        repetition_penalty_type_ = runtime_args->isExist("repetition_penalty") ? RepetitionPenaltyType::Multiplicative :
177	                                                                                 RepetitionPenaltyType::Additive;
178	        Tensor repetition_penalty = repetition_penalty_type_ == RepetitionPenaltyType::Multiplicative ?
179	                                        runtime_args->at("repetition_penalty") :
180	                                        runtime_args->at("presence_penalty");
181	        if (repetition_penalty.size() == 1) {
182	            float rp = repetition_penalty.getVal<float>();
183	            deviceFill(repetition_penalty_buf_, batch_size, rp, stream_);
184	            std::fill_n(repetition_penalty_, batch_size, rp);
185	        }
186	        else {
187	            cudaAutoCpy(repetition_penalty_buf_, repetition_penalty.getPtr<float>(), batch_size, stream_);
188	            std::copy_n(repetition_penalty.getPtr<float>(), batch_size, repetition_penalty_);
189	        }
190	    }
191	    else {
192	        repetition_penalty_type_ = RepetitionPenaltyType::None;
193	    }
194	
195	    const int default_min_length = 0;
196	    Tensor    min_lengths = runtime_args->at("min_length", Tensor(MEMORY_CPU, TYPE_INT32, {1}, &default_min_length));
197	    if (min_lengths.size() == 1) {
198	        int minlen = min_lengths.getVal<int>();
199	        deviceFill(min_lengths_buf_, batch_size, minlen, stream_);
200	        std::fill_n(min_lengths_, batch_size, minlen);
201	    }
202	    else {
203	        cudaAutoCpy(min_lengths_buf_, min_lengths.getPtr<int>(), batch_size, stream_);
204	        std::copy_n(min_lengths.getPtr<int>(), batch_size, min_lengths_);
205	    }
206	}
