209	void BaseSamplingLayer<T>::forward(std::vector<Tensor>* output_tensors, const std::vector<Tensor>* input_tensors)
210	{
211	    // input_tensors:
212	    //      logits [local_batch_size, vocab_size_padded]
213	    //      embedding_bias [vocab_size_padded]
214	    //      step [1] on cpu
215	    //      max_input_length [1] on cpu
216	    //      input_lengths [local_batch_size]
217	    //      ite [1] on cpu
218	    //      random_seed [1] on cpu, optional
219	
220	    // output_tensors:
221	    //      output_ids [max_seq_len, batch_size]
222	    //      finished [local_batch_size]
223	    //      sequence_length [local_batch_size]
224	    //      cum_log_probs [local_batch_size], must be float*
225	
226	    FT_CHECK(false);  // TODO deprecated, need to remove
227	    std::unordered_map<std::string, Tensor> input_tensors_map{{"logits", input_tensors->at(0)},
228	                                                              {"embedding_bias", input_tensors->at(1)},
229	                                                              {"step", input_tensors->at(2)},
230	                                                              {"max_input_length", input_tensors->at(3)},
231	                                                              {"input_lengths", input_tensors->at(4)},
232	                                                              {"ite", input_tensors->at(5)}};
233	    if (input_tensors->size() == 7) {
234	        input_tensors_map.insert({"random_seed", input_tensors->at(6)});
235	    }
236	
237	    std::unordered_map<std::string, Tensor> output_tensors_map{{"output_ids", output_tensors->at(0)},
238	                                                               {"finished", output_tensors->at(1)},
239	                                                               {"sequence_length", output_tensors->at(2)},
240	                                                               {"cum_log_probs", output_tensors->at(3)}};
241	    forward(&output_tensors_map, &input_tensors_map);
242	}
