244	template<typename T>
245	void BaseSamplingLayer<T>::forward(std::unordered_map<std::string, Tensor>*       output_tensors,
246	                                   const std::unordered_map<std::string, Tensor>* input_tensors)
247	{
248	    FT_LOG_DEBUG("%s", __PRETTY_FUNCTION__);
249	    TensorMap input_map(*input_tensors);
250	    TensorMap output_map(*output_tensors);
251	    forward(&output_map, &input_map);
