254	template<typename T>
255	void BaseSamplingLayer<T>::forward(TensorMap* output_tensors, TensorMap* input_tensors)
256	{
257	    // input_tensors:
258	    //      logits [local_batch_size, vocab_size_padded]
259	    //      embedding_bias [vocab_size_padded], optional
260	    //      step [1] on cpu
261	    //      max_input_length [1] on cpu
262	    //      input_lengths [local_batch_size], optional
263	    //      ite [1] on cpu
264	    //      end_id [local_batch_size], optional
265	
266	    // output_tensors:
267	    //      output_ids [max_seq_len, batch_size]
268	    //      finished [local_batch_size], optional
269	    //      sequence_length [local_batch_size], optional
270	    //      cum_log_probs [batch_size], must be float*, optional
271	    //          The cumultative log probability of generated tokens.
272	    //      output_log_probs [local_batch_size], must be float*, optional
273	    //          The log probs at the current step.
274	
275	    FT_LOG_DEBUG("%s start", __PRETTY_FUNCTION__);
276	    FT_CHECK(input_tensors->size() >= 4);
277	    FT_CHECK(output_tensors->size() >= 1);
278	    const int batch_size       = output_tensors->at("output_ids").shape[1];
279	    const int local_batch_size = input_tensors->at("logits").shape[0];
280	    const int step             = input_tensors->at("step").getVal<int>();
281	    const int ite              = input_tensors->at("ite").getVal<int>();
282	    const int max_input_length = input_tensors->at("max_input_length").getVal<int>();
283	    T*        logits           = input_tensors->at("logits").getPtr<T>();
284	
285	#define ALL_OF(p_, sz_, dt_, v_) (std::all_of(p_, p_ + sz_, [&](dt_ b) { return b == v_; }))
286	
287	    bool* skip_decode = skip_decode_ + ite * local_batch_size;
288	    if (ALL_OF(skip_decode, local_batch_size, bool, true)) {
289	        // No sample in the current batch to do TopX sampling.
290	        return;
291	    }
292	    skip_any_ = std::any_of(skip_decode, skip_decode + local_batch_size, [](bool b) { return b; });
293	    if (skip_any_) {
294	        // A TopX Sampling layer directly changes the logit values. In case of skip_any==true,
295	        // meaning topk and topp layers will run simultaneously for a batch in the same step.
296	        // We copy the logits to an internal buffer, not affecting the other sampling layers.
297	        FT_CHECK(input_tensors->at("logits").size() == local_batch_size * vocab_size_padded_);
298	        cudaD2Dcpy(runtime_logits_buf_, logits, input_tensors->at("logits").size());
299	        logits = runtime_logits_buf_;
300	    }
301	
302	    const T* embedding_bias =
303	        input_tensors->isExist("embedding_bias") ? input_tensors->at("embedding_bias").getPtr<T>() : nullptr;
304	    if (embedding_bias != nullptr || !ALL_OF(temperature_ + ite * local_batch_size, local_batch_size, float, 1.0f)) {
305	        invokeBatchApplyTemperaturePenalty(logits,
306	                                           embedding_bias,
307	                                           temperature_buf_ + ite * local_batch_size,
308	                                           local_batch_size,
309	                                           vocab_size_,
310	                                           vocab_size_padded_,
311	                                           stream_);
312	    }
313	    sync_check_cuda_error();
314	
315	    if (step > 1 && repetition_penalty_type_ != RepetitionPenaltyType::None) {
316	        float default_value = getDefaultPenaltyValue(repetition_penalty_type_);
317	        if (!ALL_OF(repetition_penalty_ + ite * local_batch_size, local_batch_size, float, default_value)) {
318	            invokeBatchApplyRepetitionPenalty(
319	                logits,
320	                repetition_penalty_buf_ + ite * local_batch_size,
321	                output_tensors->at("output_ids").getPtrWithOffset<int>(ite * local_batch_size),
322	                batch_size,
323	                local_batch_size,
324	                vocab_size_padded_,
325	                input_tensors->at("input_lengths", Tensor{MEMORY_GPU, TYPE_INT32, {}, nullptr}).getPtr<int>(),
326	                max_input_length,
327	                step,
328	                repetition_penalty_type_,
329	                stream_);
330	            sync_check_cuda_error();
331	        }
332	    }
333	
334	    const int  num_generated_tokens      = step - max_input_length;
335	    const int* min_lengths               = min_lengths_ + ite * local_batch_size;
336	    const bool invoke_min_length_penalty = std::any_of(
337	        min_lengths, min_lengths + local_batch_size, [&](int min_length) { return min_length > num_generated_tokens; });
338	    if (invoke_min_length_penalty) {
339	        FT_CHECK_WITH_INFO(input_tensors->isExist("end_id"), "Need end_id to apply min length penlaty");
340	        invokeMinLengthPenalty(logits,
341	                               min_lengths_buf_ + ite * local_batch_size,
342	                               input_tensors->getPtr<const int>("end_id"),
343	                               output_tensors->getPtr<const int>("sequence_length"),
344	                               max_input_length,
345	                               local_batch_size,
346	                               vocab_size_padded_,
347	                               stream_);
348	        sync_check_cuda_error();
349	    }
350	#undef ALL_OF
351	
352	    runSampling(output_tensors, input_tensors);
353	
354	    if (is_free_buffer_after_forward_) {
355	        freeBuffer();
356	    }
357	    sync_check_cuda_error();
358	    FT_LOG_DEBUG("%s stop", __PRETTY_FUNCTION__);
359	}
