129	
130	template<typename T, int BLOCK_SIZE_, int BLOCKS_PER_BEAM_>
131	__global__ void topk_stage1(const T* __restrict log_probs,
132	                            T*          tmp_log_probs,
133	                            int*        topk_tmp_id_buf,
134	                            T*          topk_tmp_val_buf,
135	                            const bool* finished,
136	                            const int   max_top_k,
137	                            const int*  top_ks,
138	                            const int   vocab_size,
139	                            const int*  end_ids,
140	                            const bool* skip_decode)
141	{
142	    typedef cub::BlockReduce<TopK_2<T>, BLOCK_SIZE_> BlockReduce;
143	    __shared__ typename BlockReduce::TempStorage     temp_storage;
144	
145	    const int tid = threadIdx.x;
146	    const int bid = blockIdx.x;
147	
148	    const int batch_id = bid / BLOCKS_PER_BEAM_;  // row id for log_probs
149	    if (skip_decode != nullptr && skip_decode[batch_id]) {
150	        return;
151	    }
152	    const int block_lane = bid % BLOCKS_PER_BEAM_;                              // block id for a beam
153	    const int k          = (top_ks != nullptr) ? top_ks[batch_id] : max_top_k;  // batch_id = batch index
154	
155	    const int tmp_log_buf_index  = batch_id * vocab_size;
156	    const int tmp_topk_buf_index = batch_id * BLOCKS_PER_BEAM_ * max_top_k + block_lane * k;
157	
158	    TopK_2<T>  partial;
159	    const bool IS_FP16   = std::is_same<T, half>::value;
160	    const T    MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
161	
162	    if (finished != nullptr && finished[batch_id] == true) {
163	        if (tid < k) {
164	            const int index = tmp_topk_buf_index + tid;
165	            if (block_lane == 0 && tid == 0) {
166	                const int end_id        = end_ids[batch_id];
167	                topk_tmp_id_buf[index]  = tmp_log_buf_index + end_id;
168	                topk_tmp_val_buf[index] = log_probs[tmp_log_buf_index + end_id];
169	            }
170	            else {
171	                topk_tmp_id_buf[index]  = -1;
172	                topk_tmp_val_buf[index] = -MAX_T_VAL;
173	            }
174	        }
175	        return;
176	    }
177	
178	    for (int elem_id = tid + block_lane * BLOCK_SIZE_; elem_id < vocab_size;
179	         elem_id += BLOCK_SIZE_ * BLOCKS_PER_BEAM_) {
180	        int index            = elem_id + tmp_log_buf_index;
181	        tmp_log_probs[index] = log_probs[index];
182	    }
183	
184	    for (int ite = 0; ite < k; ite++) {
185	        partial.init();
186	#pragma unroll
187	        for (int elem_id = tid + block_lane * BLOCK_SIZE_; elem_id < vocab_size;
188	             elem_id += BLOCK_SIZE_ * BLOCKS_PER_BEAM_) {
189	            int index = elem_id + tmp_log_buf_index;
190	            partial.insert(tmp_log_probs[index], index);
191	        }
192	
193	        TopK_2<T> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op_2<T>);
194	
195	        if (tid == 0) {
196	            const int index         = tmp_topk_buf_index + ite;
197	            topk_tmp_id_buf[index]  = total.p;
198	            topk_tmp_val_buf[index] = total.u;
199	            tmp_log_probs[total.p]  = -MAX_T_VAL;
200	        }
201	        __syncthreads();
202	    }
203	}
204	
205	template<typename T, int BLOCK_SIZE_, int BLOCKS_PER_BEAM_>
206	__global__ void topk_stage2_sampling(const int* __restrict topk_tmp_id_buf,
207	                                     T*             topk_tmp_val_buf,
208	                                     int*           ids,
209	                                     int*           sequence_length,
210	                                     bool*          finished,
211	                                     float*         cum_log_probs,
212	                                     float*         output_log_probs,
213	                                     const int      max_top_k,
214	                                     const int*     top_ks,
215	                                     const float    top_p,
216	                                     const float*   top_ps,
217	                                     curandState_t* curandstate,
218	                                     const int*     end_ids,
219	                                     const int      vocab_size,
220	                                     const bool*    skip_decode)
221	{
222	    const bool IS_FP16   = std::is_same<T, half>::value;
223	    const T    MAX_T_VAL = (IS_FP16) ? HALF_FLT_MAX : FLT_MAX;
224	
225	    const int tid      = threadIdx.x;
226	    const int batch_id = blockIdx.x;
227	    if (skip_decode != nullptr && skip_decode[batch_id]) {
228	        return;
229	    }
230	
231	    const int   k              = (top_ks != nullptr) ? top_ks[batch_id] : max_top_k;
232	    const float prob_threshold = (top_ps != nullptr) ? top_ps[batch_id] : top_p;
233	    const int   size           = k * BLOCKS_PER_BEAM_;
234	    const int   stride         = max_top_k * BLOCKS_PER_BEAM_;
235	
236	    typedef cub::BlockReduce<TopK_2<float>, BLOCK_SIZE_> BlockReduce;
237	    __shared__ typename BlockReduce::TempStorage         temp_storage;
238	    extern __shared__ char                               array[];
239	    __shared__ float                                     rand_num;
240	    __shared__ float                                     s_sum;
241	    __shared__ float                                     s_max;
242	    T*                                                   s_val = topk_tmp_val_buf + batch_id * stride;
243	    int*                                                 s_id  = reinterpret_cast<int*>(array);
244	    if (tid == 0) {
245	        s_sum = 0.0f;
246	    }
247	    TopK_2<float> partial;
248	
249	    if (finished != nullptr && finished[batch_id] == true) {
250	        ids[batch_id] = end_ids[batch_id];
251	        return;
252	    }
253	
254	    float* s_val2 = reinterpret_cast<float*>(s_id + k);
255	    for (int ite = 0; ite < k; ite++) {
256	        partial.init();
257	#pragma unroll
258	        for (int i = tid; i < size; i += BLOCK_SIZE_) {
259	            partial.insert((float)s_val[i], i);
260	        }
261	
262	        TopK_2<float> total = BlockReduce(temp_storage).Reduce(partial, reduce_topk_op_2<float>);
263	
264	        if (tid == 0) {
265	            if (ite == 0) {
266	                s_max = total.u;
267	            }
268	            s_id[ite]      = total.p;
269	            s_val[total.p] = -MAX_T_VAL;
270	
271	            // when cum_log_probs are computed, topk_tmp_val_buf (logits_buf_) are already pre-processed by
272	            // softmax_kernel
273	            if (cum_log_probs == nullptr && output_log_probs == nullptr) {
274	                total.u = __expf(total.u - s_max);
275	            }
276	            s_val2[ite] = total.u;
277	            s_sum += total.u;
278	        }
279	        __syncthreads();
280	    }
281	
282	    if (tid == 0) {
283	        rand_num = (float)curand_uniform(curandstate + blockIdx.x) * prob_threshold * s_sum;
284	        for (int i = 0; i < k; i++) {
285	            float exp_logit = s_val2[i];
286	            rand_num        = rand_num - exp_logit;
287	            if (rand_num <= 0.0f || i == k - 1) {
288	                ids[batch_id] = topk_tmp_id_buf[batch_id * stride + s_id[i]] % vocab_size;
289	                if (cum_log_probs != nullptr || output_log_probs != nullptr) {
290	                    float log_prob = logf(exp_logit);
291	                    if (cum_log_probs != nullptr) {
292	                        cum_log_probs[batch_id] += log_prob;
293	                    }
