904	    constexpr int WARP_SIZE      = 32;
905	    constexpr int NUM_WARPS      = BLOCK_SIZE / WARP_SIZE;
906	    const int     lane_id        = threadIdx.x % WARP_SIZE;
907	    const int     warp_id        = threadIdx.x / WARP_SIZE;
908	    const float   prob_threshold = (top_ps != nullptr) ? top_ps[batch_id] : top_p;
909	
910	    if (threadIdx.x == 0) {
911	        stop_shared = 0;
912	        rand_num_s  = curand_uniform(curandstate + blockIdx.x) * prob_threshold;
913	    }
914	
915	    // if begin_offset_buf and offset_buf of sorting have same value,
916	    // this means that we have find best one in beam_topK_kernel_for_topP
917	    // and skip the sorting. So, we can skip then during sampling.
918	    if (begin_offset_buf[batch_id] == offset_buf[batch_id]) {
919	        if (tid == 0) {
920	            int offset    = batch_id * vocab_size;
921	            ids[batch_id] = sorted_id_vals[offset];
